import React from "react";

function Sidebar({ darkMode, setDarkMode, activeSection, setActiveSection }) {
  return (
    <aside className="sidebar">
      <div className="sidebar-brand">
        <h2>🏋️ FitCare</h2>
        <p>Premium Fitness Panel</p>
      </div>

      <div className="sidebar-menu">
        <div
          className={`menu-item ${activeSection === "dashboard" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("dashboard")}
        >
          🏠 Dashboard
        </div>

        <div
          className={`menu-item ${activeSection === "bmi" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("bmi")}
        >
          📊 BMI Tracker
        </div>

        <div
          className={`menu-item ${activeSection === "trainer" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("trainer")}
        >
          🧠 AI Trainer
        </div>

        <div
          className={`menu-item ${activeSection === "chatbot" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("chatbot")}
        >
          💬 AI Chatbot
        </div>

        <div
          className={`menu-item ${activeSection === "recommendation" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("recommendation")}
        >
          🎥 Exercise Videos
        </div>

        <div
          className={`menu-item ${activeSection === "progress" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("progress")}
        >
          📈 Workout Progress
        </div>

        <div
          className={`menu-item ${activeSection === "profile" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("profile")}
        >
          👤 Profile Card
        </div>

        <div
          className={`menu-item ${activeSection === "plans" ? "active-menu" : ""}`}
          onClick={() => setActiveSection("plans")}
        >
          🏋️ Workout Plans
        </div>
      </div>

      <div className="theme-toggle-box">
        <p>Theme Mode</p>
        <button onClick={() => setDarkMode(!darkMode)}>
          {darkMode ? "☀️ Light Mode" : "🌙 Dark Mode"}
        </button>
      </div>
    </aside>
  );
}

export default Sidebar;
